package com.stockmind.infrastructure.risk;
import com.fasterxml.jackson.databind.*;import com.stockmind.application.risk.*;import com.stockmind.infrastructure.eastmoney.EastmoneyRequestGate;import java.math.*;import java.net.*;import java.net.http.*;import java.nio.charset.StandardCharsets;import java.time.*;import java.util.*;import org.springframework.beans.factory.annotation.*;import org.springframework.stereotype.Component;
/** Loads current-only lockup, margin, holder and block-trade risk observations. */
@Component public final class EastmoneySupplementalRiskProvider implements SupplementalRiskProvider{private final HttpClient client;private final ObjectMapper mapper;private final String endpoint;private final EastmoneyRequestGate gate;/** Creates the production adapter using the shared Eastmoney request gate. */@Autowired public EastmoneySupplementalRiskProvider(@Value("${stockmind.risk.eastmoney.url:https://datacenter-web.eastmoney.com/api/data/v1/get}")String endpoint,EastmoneyRequestGate gate){this(HttpClient.newHttpClient(),new ObjectMapper(),endpoint,gate);}EastmoneySupplementalRiskProvider(HttpClient c,ObjectMapper m,String e,EastmoneyRequestGate g){client=c;mapper=m;endpoint=e;gate=g;}/** Aggregates four Eastmoney datasets; failures are propagated for snapshot-level degradation. */public SupplementalRiskSnapshot load(String symbol,LocalDate asOf){String code=symbol.substring(symbol.length()-6);List<String>limits=new ArrayList<>();try{List<JsonNode>lock=rows("RPT_LIFT_STAGE",code),margin=rows("RPTA_WEB_RZRQ_GGMX",code),holders=rows("RPT_HOLDERNUMLATEST",code),blocks=rows("RPT_DATA_BLOCKTRADE",code);BigDecimal l30=sumRatios(lock,asOf,asOf.plusDays(30)),l90=sumRatios(lock,asOf,asOf.plusDays(90)),mc=change(margin,"RZYE",20),hc=holderChange(holders),bd=average(blocks,"PREMIUM_RATIO",20);return new SupplementalRiskSnapshot(asOf,true,l30,l90,mc,hc,bd,List.of("eastmoney_lockup","eastmoney_margin","eastmoney_holders","eastmoney_block_trade"),limits);}catch(Exception e){throw new IllegalStateException("东方财富补充风险接口调用失败",e);}}
 private List<JsonNode>rows(String report,String code)throws Exception{String field="RPTA_WEB_RZRQ_GGMX".equals(report)?"SCODE":"SECURITY_CODE",sort="RPTA_WEB_RZRQ_GGMX".equals(report)?"&sortColumns=DATE&sortTypes=-1":"";String q="reportName="+report+"&columns=ALL&filter="+URLEncoder.encode("("+field+"=\""+code+"\")",StandardCharsets.UTF_8)+"&pageNumber=1&pageSize=100"+sort+"&source=WEB&client=WEB";HttpRequest req=HttpRequest.newBuilder(URI.create(endpoint+"?"+q)).GET().build();var r=gate.get(client,req);if(r.statusCode()<200||r.statusCode()>=300)throw new IllegalStateException("status="+r.statusCode());JsonNode n=mapper.readTree(r.body()).path("result").path("data");List<JsonNode>x=new ArrayList<>();if(n.isArray())n.forEach(x::add);return x;}
 private BigDecimal sumRatios(List<JsonNode>r,LocalDate from,LocalDate to){BigDecimal sum=BigDecimal.ZERO;for(JsonNode n:r){LocalDate d=date(n,"FREE_DATE","LIFT_DATE");BigDecimal v=decimal(n,"TOTAL_RATIO","LIFT_MARKET_CAP_RATIO","CURRENT_FREE_RATIO");if(d!=null&&v!=null&&!d.isBefore(from)&&!d.isAfter(to))sum=sum.add(v.movePointLeft(2));}return sum;}private BigDecimal holderChange(List<JsonNode>r){if(r.isEmpty())return null;BigDecimal z=FactorSupportProxy.div(decimal(r.getFirst(),"HOLDER_NUM"),decimal(r.getFirst(),"PRE_HOLDER_NUM"));return z==null?null:z.subtract(BigDecimal.ONE);}private BigDecimal change(List<JsonNode>r,String field,int count){List<BigDecimal>v=r.stream().limit(count).map(x->decimal(x,field)).filter(Objects::nonNull).toList();if(v.size()<2)return null;BigDecimal z=FactorSupportProxy.div(v.getFirst(),v.getLast());return z==null?null:z.subtract(BigDecimal.ONE);}private BigDecimal average(List<JsonNode>r,String field,int count){List<BigDecimal>v=r.stream().limit(count).map(x->decimal(x,field)).filter(Objects::nonNull).toList();return v.isEmpty()?null:v.stream().reduce(BigDecimal.ZERO,BigDecimal::add).divide(BigDecimal.valueOf(v.size()),8,RoundingMode.HALF_UP).movePointLeft(2);}private LocalDate date(JsonNode n,String...f){for(String x:f)try{String s=n.path(x).asText();if(!s.isBlank())return LocalDate.parse(s.substring(0,10));}catch(Exception ignored){}return null;}private BigDecimal decimal(JsonNode n,String...f){for(String x:f)try{String s=n.path(x).asText();if(!s.isBlank()&&!"-".equals(s))return new BigDecimal(s);}catch(Exception ignored){}return null;}private static final class FactorSupportProxy{static BigDecimal div(BigDecimal a,BigDecimal b){return a==null||b==null||b.signum()==0?null:a.divide(b,8,RoundingMode.HALF_UP);}}
}
